effect.shader:
void main() {
    if( strength <= 0.0001 ) {
        gl_FragColor = texture2DCv(inputImg.texture,acScreenNorm);
    } else {
        if( acPass==0 ) {
            gl_FragColor = texture2DCv(inputImg.texture,acScreenNorm);
        } else if( acPass==1 ) {

            float actualStrength = strength/10.0;
            vec2 texelSize = 1.0 / getTexSize(ds1.size);
            vec2 velocity = vec2(actualStrength,0.0);
            float speed = length(velocity / texelSize);
            int nSamples = int(clamp(speed, 2.01, 150.01));
            vec4 outColor = texture2DCv(ds1.texture,acScreenNorm.st);
            for(int i=1; i<nSamples; i++ ) {
                vec2 offset = velocity * (float(i) / float(nSamples - 1));
                outColor += texture2DCv(ds1.texture, acScreenNorm.st+offset);
                outColor += texture2DCv(ds1.texture, acScreenNorm.st-offset);
            }
            vec4 result = outColor/float(nSamples*2-1);
            gl_FragColor = result;
        } else {

            float actualStrength = strength/10.0;

            vec2 texelSize = 1.0 / getTexSize(hblur.size);
            vec2 velocity = vec2(0.0,actualStrength);
            float speed = length(velocity / texelSize);
            int nSamples = int(clamp(speed, 2.01, 150.01));
            vec4 outColor = texture2DCv(hblur.texture,acScreenNorm.st);
            for(int i=1; i<nSamples; i++ ) {
                vec2 offset = velocity * (float(i) / float(nSamples - 1));
                outColor += texture2DCv(hblur.texture, acScreenNorm.st+offset);
                outColor += texture2DCv(hblur.texture, acScreenNorm.st-offset);
            }
            vec4 result = outColor/float(nSamples*2-1);
            gl_FragColor = result;

        }
    }
}
